mapper.select:
select lead_id, user_id, product_id, product_name, category_id, name, phone, region_id, status, assigned_to, follow_note, create_time, update_time from bh_lead where del_flag = '0'
and region_id = #{regionId}
and status = #{status}
and category_id = #{categoryId}
and assigned_to = #{assignedTo}
and create_time >= #{startDate}
and create_time <= #{endDate}
order by lead_id desc

select count(1)
from bh_lead
where del_flag = '0'
  and phone = #{phone}

      and product_id = #{productId}


      and user_id = #{userId}

  and create_time  >=  date_sub(now(), interval 24 hour)
